{
  "name": "RRNET Manager",
  "description": "A comprehensive ISP management dashboard for RRNET to manage clients, PPPoE plans, billing, and automated WhatsApp notifications.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ClientStatus {
  ACTIVE = 'ACTIVE',
  CUT = 'CUT',
  SUSPENDED = 'SUSPENDED'
}

export enum InvoiceStatus {
  PAID = 'PAID',
  PENDING = 'PENDING',
  OVERDUE = 'OVERDUE'
}

export interface Plan {
  id: string;
  name: string;
  speed: string; // e.g., "10 Mbps"
  price: number;
}

export interface Client {
  id: string;
  firstName: string;
  lastName: string;
  phone: string;
  idNumber: string;
  planId: string;
  pppoeUser: string;
  addressList: string;
  status: ClientStatus;
  createdAt: string;
}

export interface Invoice {
  id: string;
  clientId: string;
  amount: number;
  dueDate: string;
  status: InvoiceStatus;
  period: string; // e.g., "2023-10"
  paidAt?: string;
}

export interface MessageLog {
  id: string;
  clientId: string;
  type: 'INVOICE_SENT' | 'REMINDER' | 'RECEIPT';
  timestamp: string;
  status: 'SENT' | 'FAILED';
}

import { Client, Plan, Invoice, ClientStatus } from '../types';

const KEYS = {
  CLIENTS: 'rrnet_clients',
  PLANS: 'rrnet_plans',
  INVOICES: 'rrnet_invoices',
};

const DEFAULT_PLANS: Plan[] = [
  { id: 'p1', name: 'Plan Básico', speed: '10 Mbps', price: 15.00 },
  { id: 'p2', name: 'Plan Estándar', speed: '20 Mbps', price: 25.00 },
  { id: 'p3', name: 'Plan Premium', speed: '50 Mbps', price: 45.00 },
];

export const storageService = {
  getClients: (): Client[] => {
    const data = localStorage.getItem(KEYS.CLIENTS);
    return data ? JSON.parse(data) : [];
  },
  saveClients: (clients: Client[]) => {
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  getPlans: (): Plan[] => {
    const data = localStorage.getItem(KEYS.PLANS);
    return data ? JSON.parse(data) : DEFAULT_PLANS;
  },
  savePlans: (plans: Plan[]) => {
    localStorage.setItem(KEYS.PLANS, JSON.stringify(plans));
  },
  getInvoices: (): Invoice[] => {
    const data = localStorage.getItem(KEYS.INVOICES);
    return data ? JSON.parse(data) : [];
  },
  saveInvoices: (invoices: Invoice[]) => {
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  }
};

/**
 * RRNET Meta API Service (Simulation)
 * In a real environment, this would call:
 * https://graph.facebook.com/v17.0/YOUR_PHONE_NUMBER_ID/messages
 */

export const metaService = {
  sendWhatsAppMessage: async (phone: string, template: string, components: any[]) => {
    console.log(`[Meta API Simulation] Sending message to ${phone} using template ${template}`);
    console.log(`Components:`, components);

    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 800));

    // Return mock success
    return { success: true, message_id: `wa_${Math.random().toString(36).substr(2, 9)}` };
  },

  sendInvoiceNotification: async (clientName: string, phone: string, amount: number, dueDate: string) => {
    return metaService.sendWhatsAppMessage(phone, 'invoice_generated', [
      { type: 'body', parameters: [
        { type: 'text', text: clientName },
        { type: 'text', text: `$${amount.toFixed(2)}` },
        { type: 'text', text: dueDate }
      ]}
    ]);
  },

  sendPaymentReminder: async (clientName: string, phone: string, dueDate: string) => {
    return metaService.sendWhatsAppMessage(phone, 'payment_reminder', [
      { type: 'body', parameters: [
        { type: 'text', text: clientName },
        { type: 'text', text: dueDate }
      ]}
    ]);
  },

  sendPaymentReceipt: async (clientName: string, phone: string, amount: number, reference: string) => {
    return metaService.sendWhatsAppMessage(phone, 'payment_receipt', [
      { type: 'body', parameters: [
        { type: 'text', text: clientName },
        { type: 'text', text: `$${amount.toFixed(2)}` },
        { type: 'text', text: reference }
      ]}
    ]);
  }
};

import { GoogleGenAI } from "@google/genai";
import { Client, Invoice, Plan } from "../types";

export const getBusinessInsights = async (clients: Client[], invoices: Invoice[], plans: Plan[]) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const pendingInvoices = invoices.filter(inv => inv.status !== 'PAID');
    const totalExpected = invoices.reduce((acc, inv) => acc + inv.amount, 0);
    const totalReceived = invoices.filter(inv => inv.status === 'PAID').reduce((acc, inv) => acc + inv.amount, 0);

    const prompt = `
      Act as a business consultant for RRNET, a small ISP. 
      Analyze the following current state:
      - Total Clients: ${clients.length}
      - Total Invoices: ${invoices.length}
      - Pending Invoices: ${pendingInvoices.length}
      - Total Revenue Expected: $${totalExpected}
      - Total Revenue Received: $${totalReceived}
      - Top Plans: ${plans.map(p => p.name).join(', ')}

      Provide a 2-sentence summary of the business health and 2 actionable recommendations to improve collections or growth.
      Keep it professional and concise in Spanish.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "No se pudieron obtener insights en este momento.";
  }
};

import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Users, 
  Wifi, 
  Receipt, 
  BarChart3, 
  Settings, 
  Menu,
  X,
  Bell
} from 'lucide-react';

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isSidebarOpen, setIsSidebarOpen] = React.useState(false);
  const location = useLocation();

  const menuItems = [
    { name: 'Dashboard', icon: LayoutDashboard, path: '/' },
    { name: 'Clientes', icon: Users, path: '/clients' },
    { name: 'Planes', icon: Wifi, path: '/plans' },
    { name: 'Facturación', icon: Receipt, path: '/billing' },
    { name: 'Reportes', icon: BarChart3, path: '/reports' },
  ];

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 w-64 bg-white border-r border-gray-200 z-50 transform transition-transform duration-300 lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <h1 className="text-2xl font-bold text-blue-600 flex items-center gap-2">
            <Wifi className="w-8 h-8" />
            RRNET
          </h1>
        </div>
        <nav className="mt-6 px-4 space-y-1">
          {menuItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${
                  isActive 
                    ? 'bg-blue-50 text-blue-600' 
                    : 'text-gray-600 hover:bg-gray-100'
                }`}
                onClick={() => setIsSidebarOpen(false)}
              >
                <item.icon className="w-5 h-5" />
                {item.name}
              </Link>
            );
          })}
        </nav>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-4 lg:px-8">
          <button 
            className="p-2 text-gray-500 lg:hidden"
            onClick={() => setIsSidebarOpen(true)}
          >
            <Menu className="w-6 h-6" />
          </button>

          <div className="flex-1 px-4 lg:px-0">
            <h2 className="text-lg font-semibold text-gray-800">
              {menuItems.find(i => i.path === location.pathname)?.name || 'Dashboard'}
            </h2>
          </div>

          <div className="flex items-center gap-4">
            <button className="p-2 text-gray-400 hover:text-gray-600 relative">
              <Bell className="w-5 h-5" />
              <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>
            <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold">
              A
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 lg:p-8">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React from 'react';
import { 
  Users, 
  DollarSign, 
  WifiOff, 
  ArrowUpRight, 
  BrainCircuit,
  Loader2
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { getBusinessInsights } from '../services/aiService';
import { ClientStatus, InvoiceStatus } from '../types';

const Dashboard: React.FC = () => {
  const clients = storageService.getClients();
  const invoices = storageService.getInvoices();
  const plans = storageService.getPlans();

  const [insights, setInsights] = React.useState<string | null>(null);
  const [loadingInsights, setLoadingInsights] = React.useState(false);

  const stats = [
    { label: 'Clientes Activos', value: clients.filter(c => c.status === ClientStatus.ACTIVE).length, icon: Users, color: 'bg-green-500' },
    { label: 'Ingresos del Mes', value: `$${invoices.filter(i => i.status === InvoiceStatus.PAID).reduce((acc, inv) => acc + inv.amount, 0).toFixed(2)}`, icon: DollarSign, color: 'bg-blue-500' },
    { label: 'Cortes Pendientes', value: clients.filter(c => c.status === ClientStatus.CUT).length, icon: WifiOff, color: 'bg-red-500' },
    { label: 'Morosidad', value: `${invoices.length > 0 ? ((invoices.filter(i => i.status === InvoiceStatus.PENDING).length / invoices.length) * 100).toFixed(1) : 0}%`, icon: ArrowUpRight, color: 'bg-yellow-500' },
  ];

  const fetchInsights = async () => {
    setLoadingInsights(true);
    const result = await getBusinessInsights(clients, invoices, plans);
    setInsights(result);
    setLoadingInsights(false);
  };

  React.useEffect(() => {
    fetchInsights();
  }, []);

  return (
    <div className="space-y-6">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-4">
              <div className={`${stat.color} p-3 rounded-lg text-white`}>
                <stat.icon className="w-6 h-6" />
              </div>
              <div>
                <p className="text-sm font-medium text-gray-500">{stat.label}</p>
                <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* AI Insights Card */}
      <div className="bg-gradient-to-r from-blue-600 to-indigo-700 rounded-xl p-6 text-white shadow-lg overflow-hidden relative">
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-4">
            <BrainCircuit className="w-6 h-6 text-blue-200" />
            <h3 className="text-lg font-semibold">Insights Estratégicos (AI)</h3>
          </div>
          {loadingInsights ? (
            <div className="flex items-center gap-2 text-blue-100">
              <Loader2 className="w-5 h-5 animate-spin" />
              <span>Analizando datos de RRNET...</span>
            </div>
          ) : (
            <p className="text-blue-50 leading-relaxed max-w-3xl">
              {insights || "Sin datos suficientes para generar insights."}
            </p>
          )}
          <button 
            onClick={fetchInsights}
            className="mt-4 px-4 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-sm transition-colors"
          >
            Actualizar Análisis
          </button>
        </div>
        {/* Background Decoration */}
        <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/2 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Recent Activity Placeholder */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
          <h3 className="font-semibold text-gray-800 mb-4">Clientes Recientes</h3>
          <div className="space-y-4">
            {clients.slice(-5).reverse().map(client => (
              <div key={client.id} className="flex items-center justify-between py-2 border-b border-gray-50 last:border-0">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center font-bold text-gray-600">
                    {client.firstName[0]}{client.lastName[0]}
                  </div>
                  <div>
                    <p className="text-sm font-medium text-gray-900">{client.firstName} {client.lastName}</p>
                    <p className="text-xs text-gray-500">{client.pppoeUser}</p>
                  </div>
                </div>
                <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                  client.status === ClientStatus.ACTIVE ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                }`}>
                  {client.status}
                </span>
              </div>
            ))}
            {clients.length === 0 && <p className="text-center text-gray-500 py-4">No hay clientes registrados.</p>}
          </div>
        </div>

        {/* Collection Status Placeholder */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
          <h3 className="font-semibold text-gray-800 mb-4">Estado de Cobranza (Este Mes)</h3>
          <div className="flex items-center justify-center h-48">
             <div className="text-center">
               <Receipt className="w-12 h-12 text-gray-300 mx-auto mb-2" />
               <p className="text-gray-500">Visualización de ingresos en construcción</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { Plus, Search, UserCheck, UserX, MessageCircle, MoreVertical, Trash2 } from 'lucide-react';
import { storageService } from '../services/storageService';
import { Client, ClientStatus, Plan } from '../types';

const Clients: React.FC = () => {
  const [clients, setClients] = React.useState<Client[]>(storageService.getClients());
  const [plans] = React.useState<Plan[]>(storageService.getPlans());
  const [searchTerm, setSearchTerm] = React.useState('');
  const [isModalOpen, setIsModalOpen] = React.useState(false);

  const [formData, setFormData] = React.useState({
    firstName: '',
    lastName: '',
    phone: '',
    idNumber: '',
    planId: plans[0]?.id || '',
    pppoeUser: '',
    addressList: 'MOROSOS'
  });

  const handleAddClient = (e: React.FormEvent) => {
    e.preventDefault();
    const newClient: Client = {
      id: crypto.randomUUID(),
      ...formData,
      status: ClientStatus.ACTIVE,
      createdAt: new Date().toISOString()
    };
    const updated = [...clients, newClient];
    setClients(updated);
    storageService.saveClients(updated);
    setIsModalOpen(false);
    setFormData({
      firstName: '', lastName: '', phone: '', idNumber: '',
      planId: plans[0]?.id || '', pppoeUser: '', addressList: 'MOROSOS'
    });
  };

  const toggleStatus = (id: string) => {
    const updated = clients.map(c => 
      c.id === id ? { ...c, status: c.status === ClientStatus.ACTIVE ? ClientStatus.CUT : ClientStatus.ACTIVE } : c
    );
    setClients(updated);
    storageService.saveClients(updated);
  };

  const deleteClient = (id: string) => {
    if (confirm('¿Seguro que deseas eliminar este cliente?')) {
      const updated = clients.filter(c => c.id !== id);
      setClients(updated);
      storageService.saveClients(updated);
    }
  };

  const filteredClients = clients.filter(c => 
    `${c.firstName} ${c.lastName}`.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.idNumber.includes(searchTerm) ||
    c.pppoeUser.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative flex-1 w-full max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            placeholder="Buscar por nombre, ID o usuario PPPoE..."
            className="w-full pl-10 pr-4 py-2 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition-colors w-full sm:w-auto justify-center"
        >
          <Plus className="w-4 h-4" />
          Nuevo Cliente
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Cliente</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Documento / PPPoE</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Plan</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Estado</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredClients.map((client) => (
                <tr key={client.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-medium text-gray-900">{client.firstName} {client.lastName}</div>
                    <div className="text-xs text-gray-500">{client.phone}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm text-gray-700">{client.idNumber}</div>
                    <div className="text-xs font-mono text-blue-600">{client.pppoeUser}</div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm text-gray-700">
                      {plans.find(p => p.id === client.planId)?.name || 'N/A'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2.5 py-1 rounded-full text-xs font-medium inline-flex items-center gap-1 ${
                      client.status === ClientStatus.ACTIVE ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                    }`}>
                      {client.status === ClientStatus.ACTIVE ? <UserCheck className="w-3 h-3" /> : <UserX className="w-3 h-3" />}
                      {client.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <button 
                        onClick={() => toggleStatus(client.id)}
                        className={`p-2 rounded-lg transition-colors ${
                          client.status === ClientStatus.ACTIVE ? 'text-orange-500 hover:bg-orange-50' : 'text-green-500 hover:bg-green-50'
                        }`}
                        title={client.status === ClientStatus.ACTIVE ? 'Cortar servicio' : 'Activar servicio'}
                      >
                        {client.status === ClientStatus.ACTIVE ? <WifiOff className="w-4 h-4" /> : <Wifi className="w-4 h-4" />}
                      </button>
                      <button className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg">
                        <MessageCircle className="w-4 h-4" />
                      </button>
                      <button 
                        onClick={() => deleteClient(client.id)}
                        className="p-2 text-red-500 hover:bg-red-50 rounded-lg"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredClients.length === 0 && (
            <div className="p-12 text-center text-gray-500">No se encontraron clientes.</div>
          )}
        </div>
      </div>

      {/* Add Client Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <h3 className="text-xl font-bold text-gray-800">Registrar Nuevo Cliente</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                <X className="w-6 h-6" />
              </button>
            </div>
            <form onSubmit={handleAddClient} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Nombre</label>
                  <input
                    required
                    type="text"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={formData.firstName}
                    onChange={e => setFormData({...formData, firstName: e.target.value})}
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Apellido</label>
                  <input
                    required
                    type="text"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={formData.lastName}
                    onChange={e => setFormData({...formData, lastName: e.target.value})}
                  />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Teléfono (WhatsApp)</label>
                  <input
                    required
                    type="tel"
                    placeholder="+584120000000"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Documento ID</label>
                  <input
                    required
                    type="text"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={formData.idNumber}
                    onChange={e => setFormData({...formData, idNumber: e.target.value})}
                  />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase">Plan de Internet</label>
                <select
