import React from 'react';
import { 
  FileText, 
  Send, 
  CheckCircle, 
  Clock, 
  CreditCard, 
  Filter,
  ArrowRight
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { metaService } from '../services/metaService';
import { Client, Invoice, InvoiceStatus, Plan } from '../types';

const Billing: React.FC = () => {
  const [invoices, setInvoices] = React.useState<Invoice[]>(storageService.getInvoices());
  const [clients] = React.useState<Client[]>(storageService.getClients());
  const [plans] = React.useState<Plan[]>(storageService.getPlans());
  const [filter, setFilter] = React.useState<InvoiceStatus | 'ALL'>('ALL');

  const generateMonthInvoices = () => {
    const currentPeriod = new Date().toISOString().slice(0, 7); // YYYY-MM
    const existing = invoices.find(inv => inv.period === currentPeriod);

    if (existing && !confirm('Ya se generaron facturas para este periodo. ¿Generar de nuevo?')) return;

    const newInvoices: Invoice[] = clients.map(client => {
      const plan = plans.find(p => p.id === client.planId);
      return {
        id: crypto.randomUUID(),
        clientId: client.id,
        amount: plan?.price || 0,
        period: currentPeriod,
        dueDate: new Date(new Date().setDate(new Date().getDate() + 5)).toISOString(), // 5 days from now
        status: InvoiceStatus.PENDING
      };
    });

    const updated = [...invoices, ...newInvoices];
    setInvoices(updated);
    storageService.saveInvoices(updated);
    alert(`${newInvoices.length} facturas generadas correctamente.`);
  };

  const markAsPaid = async (invoiceId: string) => {
    const updated = invoices.map(inv => {
      if (inv.id === invoiceId) {
        const client = clients.find(c => c.id === inv.clientId);
        if (client) {
           metaService.sendPaymentReceipt(
             `${client.firstName} ${client.lastName}`, 
             client.phone, 
             inv.amount, 
             inv.id.slice(0, 8)
           );
        }
        return { ...inv, status: InvoiceStatus.PAID, paidAt: new Date().toISOString() };
      }
      return inv;
    });
    setInvoices(updated);
    storageService.saveInvoices(updated);
  };

  const sendReminder = async (invoice: Invoice) => {
    const client = clients.find(c => c.id === invoice.clientId);
    if (!client) return;

    await metaService.sendPaymentReminder(
      `${client.firstName} ${client.lastName}`,
      client.phone,
      new Date(invoice.dueDate).toLocaleDateString()
    );
    alert('Recordatorio enviado por WhatsApp');
  };

  const filteredInvoices = invoices.filter(inv => filter === 'ALL' || inv.status === filter);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex items-center gap-2 overflow-x-auto pb-2 w-full md:w-auto">
          <button 
            onClick={() => setFilter('ALL')}
            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap ${filter === 'ALL' ? 'bg-blue-600 text-white' : 'bg-white text-gray-600 border border-gray-200'}`}
          >
            Todas
          </button>
          <button 
            onClick={() => setFilter(InvoiceStatus.PENDING)}
            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap ${filter === InvoiceStatus.PENDING ? 'bg-orange-600 text-white' : 'bg-white text-gray-600 border border-gray-200'}`}
          >
            Pendientes
          </button>
          <button 
            onClick={() => setFilter(InvoiceStatus.PAID)}
            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap ${filter === InvoiceStatus.PAID ? 'bg-green-600 text-white' : 'bg-white text-gray-600 border border-gray-200'}`}
          >
            Pagadas
          </button>
        </div>
        <button 
          onClick={generateMonthInvoices}
          className="bg-blue-600 text-white px-6 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition-colors shadow-sm font-medium w-full md:w-auto justify-center"
        >
          <FileText className="w-4 h-4" />
          Generar Facturas del Mes
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Cliente</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Monto / Periodo</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Vencimiento</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Estado</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredInvoices.slice().reverse().map((inv) => {
                const client = clients.find(c => c.id === inv.clientId);
                return (
                  <tr key={inv.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-medium text-gray-900">{client?.firstName} {client?.lastName}</div>
                      <div className="text-xs text-gray-500">{client?.pppoeUser}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-900">${inv.amount.toFixed(2)}</div>
                      <div className="text-xs text-gray-500">{inv.period}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-1 text-sm text-gray-600">
                        <Clock className="w-3 h-3" />
                        {new Date(inv.dueDate).toLocaleDateString()}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2.5 py-1 rounded-full text-xs font-medium inline-flex items-center gap-1 ${
                        inv.status === InvoiceStatus.PAID ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
                      }`}>
                        {inv.status === InvoiceStatus.PAID ? <CheckCircle className="w-3 h-3" /> : <Clock className="w-3 h-3" />}
                        {inv.status === InvoiceStatus.PAID ? 'PAGADO' : 'PENDIENTE'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2">
                        {inv.status === InvoiceStatus.PENDING && (
                          <>
                            <button 
                              onClick={() => sendReminder(inv)}
                              className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg flex items-center gap-1 text-sm"
                              title="Enviar Recordatorio WhatsApp"
                            >
                              <Send className="w-4 h-4" />
                            </button>
                            <button 
                              onClick={() => markAsPaid(inv.id)}
                              className="p-2 text-green-600 hover:bg-green-50 rounded-lg flex items-center gap-1 text-sm"
                              title="Registrar Pago"
                            >
                              <CreditCard className="w-4 h-4" />
                            </button>
                          </>
                        )}
                        {inv.status === InvoiceStatus.PAID && (
                          <div className="text-xs text-gray-400 italic">
                            Pagado el {new Date(inv.paidAt!).toLocaleDateString()}
                          </div>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredInvoices.length === 0 && (
            <div className="p-12 text-center text-gray-500">No hay facturas registradas.</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Billing;

import React from 'react';
import { Plus, Wifi, Edit2, Trash2, Zap } from 'lucide-react';
import { storageService } from '../services/storageService';
import { Plan } from '../types';

const Plans: React.FC = () => {
  const [plans, setPlans] = React.useState<Plan[]>(storageService.getPlans());

  const addPlan = () => {
    const name = prompt('Nombre del Plan:');
    const speed = prompt('Velocidad (ej: 20 Mbps):');
    const price = prompt('Precio Mensual:');

    if (name && speed && price) {
      const newPlan: Plan = {
        id: crypto.randomUUID(),
        name,
        speed,
        price: parseFloat(price)
      };
      const updated = [...plans, newPlan];
      setPlans(updated);
      storageService.savePlans(updated);
    }
  };

  const deletePlan = (id: string) => {
    if (confirm('¿Deseas eliminar este plan?')) {
      const updated = plans.filter(p => p.id !== id);
      setPlans(updated);
      storageService.savePlans(updated);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        <button 
          onClick={addPlan}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition-colors shadow-sm"
        >
          <Plus className="w-4 h-4" />
          Crear Plan
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {plans.map((plan) => (
          <div key={plan.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col">
            <div className="p-6 flex-1">
              <div className="flex items-center justify-between mb-4">
                <div className="bg-blue-50 p-3 rounded-xl text-blue-600">
                  <Wifi className="w-6 h-6" />
                </div>
                <div className="flex gap-2">
                  <button className="p-2 text-gray-400 hover:text-blue-500 transition-colors">
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button 
                    onClick={() => deletePlan(plan.id)}
                    className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-1">{plan.name}</h3>
              <div className="flex items-center gap-2 text-blue-600 font-medium mb-6">
                <Zap className="w-4 h-4" />
                {plan.speed}
              </div>
              <div className="flex items-baseline gap-1">
                <span className="text-3xl font-bold text-gray-900">${plan.price.toFixed(2)}</span>
                <span className="text-gray-500 text-sm">/mes</span>
              </div>
            </div>
            <div className="p-4 bg-gray-50 border-t border-gray-100">
               <div className="flex justify-between text-sm">
                 <span className="text-gray-500">Corte Automático</span>
                 <span className="text-green-600 font-medium">Habilitado</span>
               </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

