import React from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Download, Filter, FileSpreadsheet } from 'lucide-react';
import { storageService } from '../services/storageService';
import { InvoiceStatus } from '../types';

const Reports: React.FC = () => {
  const invoices = storageService.getInvoices();

  // Prepare data for status pie chart
  const statusData = [
    { name: 'Pagado', value: invoices.filter(i => i.status === InvoiceStatus.PAID).length },
    { name: 'Pendiente', value: invoices.filter(i => i.status === InvoiceStatus.PENDING).length },
  ];

  const COLORS = ['#10b981', '#f59e0b', '#ef4444'];

  // Prepare monthly revenue data
  const revenueByPeriod = invoices.reduce((acc: any, inv) => {
    if (inv.status === InvoiceStatus.PAID) {
      acc[inv.period] = (acc[inv.period] || 0) + inv.amount;
    }
    return acc;
  }, {});

  const revenueData = Object.keys(revenueByPeriod).sort().map(period => ({
    period,
    revenue: revenueByPeriod[period]
  }));

  const totalCollected = invoices.filter(i => i.status === InvoiceStatus.PAID).reduce((acc, i) => acc + i.amount, 0);
  const totalPending = invoices.filter(i => i.status === InvoiceStatus.PENDING).reduce((acc, i) => acc + i.amount, 0);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Collection Summary */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="font-semibold text-gray-800 mb-6">Resumen de Cobros</h3>
          <div className="grid grid-cols-2 gap-4 mb-8">
            <div className="p-4 bg-green-50 rounded-lg">
              <p className="text-xs font-semibold text-green-600 uppercase">Recaudado</p>
              <p className="text-2xl font-bold text-green-700">${totalCollected.toFixed(2)}</p>
            </div>
            <div className="p-4 bg-orange-50 rounded-lg">
              <p className="text-xs font-semibold text-orange-600 uppercase">Pendiente</p>
              <p className="text-2xl font-bold text-orange-700">${totalPending.toFixed(2)}</p>
            </div>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-6 text-sm text-gray-600 mt-4">
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-green-500"></div> Pagado</div>
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-orange-500"></div> Pendiente</div>
          </div>
        </div>

        {/* Revenue Growth */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-semibold text-gray-800">Crecimiento de Ingresos</h3>
            <button className="text-blue-600 text-sm font-medium flex items-center gap-1">
              <Download className="w-4 h-4" /> Exportar
            </button>
          </div>
          <div className="h-[350px]">
            {revenueData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={revenueData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                  <XAxis dataKey="period" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(value) => `$${value}`} />
                  <Tooltip cursor={{fill: '#f8fafc'}} />
                  <Bar dataKey="revenue" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-gray-400">
                Aún no hay datos de ingresos registrados.
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Advanced Filter Placeholder */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between">
         <div className="flex items-center gap-3">
           <Filter className="w-5 h-5 text-gray-400" />
           <span className="text-gray-600 font-medium">Filtrar reportes detallados por fecha, zona o plan</span>
         </div>
         <button className="px-4 py-2 border border-gray-200 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-gray-50">
           <FileSpreadsheet className="w-4 h-4 text-green-600" /> Generar Excel
         </button>
      </div>
    </div>
  );
};

export default Reports;

