import React from 'react';
import { 
  Cpu, 
  Wifi, 
  MessageSquare, 
  ShieldCheck, 
  Save, 
  Plus, 
  Trash2, 
  Edit2, 
  Globe,
  Key,
  Database
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { RouterConfig, Plan, WhatsAppConfig } from '../types';

const Settings: React.FC = () => {
  const [activeTab, setActiveTab] = React.useState<'routers' | 'plans' | 'whatsapp' | 'system'>('routers');

  // States
  const [routers, setRouters] = React.useState<RouterConfig[]>(storageService.getRouters());
  const [plans, setPlans] = React.useState<Plan[]>(storageService.getPlans());
  const [waConfig, setWaConfig] = React.useState<WhatsAppConfig>(storageService.getWhatsAppConfig() || {
    accessToken: '',
    phoneNumberId: '',
    businessAccountId: ''
  });

  // Handlers for Routers
  const addRouter = () => {
    const name = prompt('Nombre del Router:');
    const host = prompt('IP o Host (ej: 192.168.1.1):');
    if (name && host) {
      const newRouter: RouterConfig = {
        id: crypto.randomUUID(),
        name,
        host,
        port: 8728,
        user: 'admin',
        pass: '',
        status: 'ONLINE'
      };
      const updated = [...routers, newRouter];
      setRouters(updated);
      storageService.saveRouters(updated);
    }
  };

  const deleteRouter = (id: string) => {
    if (confirm('¿Eliminar conexión de router?')) {
      const updated = routers.filter(r => r.id !== id);
      setRouters(updated);
      storageService.saveRouters(updated);
    }
  };

  // Handlers for Plans
  const handleAddPlan = () => {
    const name = prompt('Nombre del Plan:');
    const speed = prompt('Velocidad (ej: 50 Mbps):');
    const price = prompt('Precio Mensual ($):');
    if (name && speed && price) {
      const newPlan: Plan = {
        id: crypto.randomUUID(),
        name,
        speed,
        price: parseFloat(price)
      };
      const updated = [...plans, newPlan];
      setPlans(updated);
      storageService.savePlans(updated);
    }
  };

  const deletePlan = (id: string) => {
    if (confirm('¿Seguro que deseas eliminar este plan?')) {
      const updated = plans.filter(p => p.id !== id);
      setPlans(updated);
      storageService.savePlans(updated);
    }
  };

  // Handler for WhatsApp
  const saveWhatsApp = (e: React.FormEvent) => {
    e.preventDefault();
    storageService.saveWhatsAppConfig(waConfig);
    alert('Configuración de WhatsApp guardada correctamente.');
  };

  const tabs = [
    { id: 'routers', label: 'Routers Mikrotik', icon: Cpu },
    { id: 'plans', label: 'Planes de Internet', icon: Wifi },
    { id: 'whatsapp', label: 'API WhatsApp (Meta)', icon: MessageSquare },
    { id: 'system', label: 'Sistema', icon: ShieldCheck },
  ];

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      {/* Tabs Navigation */}
      <div className="flex items-center gap-1 bg-white p-1 rounded-xl shadow-sm border border-gray-200 overflow-x-auto no-scrollbar">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
              activeTab === tab.id 
                ? 'bg-blue-600 text-white shadow-md' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <tab.icon className="w-4 h-4" />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="min-h-[500px]">
        {activeTab === 'routers' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold text-gray-900">Nodos Mikrotik</h3>
                <p className="text-sm text-gray-500">Configura la conexión API para gestionar cortes y PPPoE.</p>
              </div>
              <button 
                onClick={addRouter}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition-colors"
              >
                <Plus className="w-4 h-4" />
                Añadir Router
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {routers.map(router => (
                <div key={router.id} className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-blue-50 p-3 rounded-lg text-blue-600">
                      <Cpu className="w-6 h-6" />
                    </div>
                    <div className="flex gap-1">
                      <button className="p-2 text-gray-400 hover:text-blue-600"><Edit2 className="w-4 h-4" /></button>
                      <button onClick={() => deleteRouter(router.id)} className="p-2 text-gray-400 hover:text-red-600"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>
                  <h4 className="font-bold text-lg text-gray-900">{router.name}</h4>
                  <p className="text-sm text-gray-500 flex items-center gap-1 mb-4">
                    <Globe className="w-3 h-3" /> {router.host}:{router.port}
                  </p>
                  <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                    <span className="text-xs font-semibold text-gray-400 uppercase">Estado API</span>
                    <span className="flex items-center gap-1.5 text-xs font-bold text-green-600">
                      <div className="w-1.5 h-1.5 bg-green-500 rounded-full"></div>
                      CONECTADO
                    </span>
                  </div>
                </div>
              ))}
              {routers.length === 0 && (
