import React from 'react';
import { 
  Box, 
  Users, 
  MapPin, 
  Zap, 
  X, 
  Search, 
  Info,
  ChevronRight,
  Activity
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { Terminal, Client } from '../types';

const NetworkMap: React.FC = () => {
  const mapRef = React.useRef<L.Map | null>(null);
  const [terminals] = React.useState<Terminal[]>(storageService.getTerminals());
  const [clients] = React.useState<Client[]>(storageService.getClients());
  const [selectedTerminal, setSelectedTerminal] = React.useState<Terminal | null>(null);

  React.useEffect(() => {
    if (!mapRef.current) {
      // Default center (can be configured in settings later)
      mapRef.current = L.map('network-map').setView([10.4806, -66.9036], 13);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
        subdomains: 'abcd',
        maxZoom: 20
      }).addTo(mapRef.current);
    }

    // Clear existing markers if any
    mapRef.current.eachLayer((layer: any) => {
      if (layer instanceof L.Marker) {
        mapRef.current?.removeLayer(layer);
      }
    });

    // Add terminals to map
    terminals.forEach(term => {
      const marker = L.marker([term.lat, term.lng], {
        icon: L.divIcon({
          className: 'custom-div-icon',
          html: `<div class="bg-blue-600 p-2 rounded-lg border-2 border-white shadow-lg text-white">
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"></path><path d="m3.3 7 8.7 5 8.7-5"></path><path d="M12 22V12"></path></svg>
                 </div>`,
          iconSize: [32, 32],
          iconAnchor: [16, 16]
        })
      }).addTo(mapRef.current!);

      marker.on('click', () => {
        setSelectedTerminal(term);
        mapRef.current?.setView([term.lat, term.lng], 16);
      });
    });

    return () => {
      if (mapRef.current) {
        // mapRef.current.remove();
      }
    };
  }, [terminals]);

  const getClientsInTerminal = (termId: string) => {
    return clients.filter(c => c.terminalId === termId);
  };

  const renderPortGrid = () => {
    if (!selectedTerminal) return null;
    const terminalClients = getClientsInTerminal(selectedTerminal.id);
    const ports = Array.from({ length: selectedTerminal.totalPorts }, (_, i) => i + 1);

    return (
      <div className="grid grid-cols-4 gap-2 mt-4">
        {ports.map(port => {
          const clientOnPort = terminalClients.find(c => c.portNumber === port);
          return (
            <div 
              key={port}
              className={`p-2 rounded-lg border-2 flex flex-col items-center justify-center transition-all ${
                clientOnPort 
                ? 'bg-blue-50 border-blue-200 text-blue-700' 
                : 'bg-gray-50 border-gray-100 text-gray-400'
              }`}
            >
              <span className="text-[10px] font-bold uppercase opacity-60">P-{port}</span>
              <Activity className={`w-4 h-4 mt-1 ${clientOnPort ? 'animate-pulse' : ''}`} />
              <div className="text-[8px] mt-1 truncate w-full text-center">
                {clientOnPort ? `${clientOnPort.lastName}` : 'LIBRE'}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="h-full relative flex">
      {/* Map View */}
      <div className="flex-1 p-4">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 h-full overflow-hidden flex flex-col">
          <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white/80 backdrop-blur-md z-10">
            <div className="flex items-center gap-2">
              <MapPin className="w-5 h-5 text-blue-600" />
              <h2 className="font-bold text-gray-800">Mapa de Cobertura y Red</h2>
            </div>
            <div className="flex gap-2">
               <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                  <input 
                    placeholder="Buscar zona o NAP..." 
                    className="pl-9 pr-4 py-1.5 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
               </div>
            </div>
          </div>
          <div className="flex-1">
             <div id="network-map"></div>
          </div>
        </div>
      </div>

      {/* Info Sidebar (Detail) */}
      <div className={`
        fixed inset-y-0 right-0 w-80 bg-white shadow-2xl z-[1000] transform transition-transform duration-300 border-l border-gray-200 flex flex-col
        ${selectedTerminal ? 'translate-x-0' : 'translate-x-full'}
      `}>
        {selectedTerminal && (
          <>
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-blue-600 text-white">
              <div>
                <h3 className="font-bold text-lg">{selectedTerminal.name}</h3>
                <p className="text-xs text-blue-100 flex items-center gap-1">
                   <Zap className="w-3 h-3" /> PON: {selectedTerminal.ponSource}
                </p>
              </div>
              <button 
                onClick={() => setSelectedTerminal(null)}
                className="p-1.5 hover:bg-white/20 rounded-lg transition-colors"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              {/* Stats Card */}
              <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 flex justify-around">
                <div className="text-center">
                   <p className="text-[10px] text-gray-500 font-bold uppercase">Capacidad</p>
                   <p className="text-xl font-bold text-gray-800">{selectedTerminal.totalPorts}</p>
                </div>
                <div className="w-px h-10 bg-gray-200"></div>
                <div className="text-center">
                   <p className="text-[10px] text-gray-500 font-bold uppercase">Ocupados</p>
                   <p className="text-xl font-bold text-blue-600">{getClientsInTerminal(selectedTerminal.id).length}</p>
                </div>
                <div className="w-px h-10 bg-gray-200"></div>
                <div className="text-center">
                   <p className="text-[10px] text-gray-500 font-bold uppercase">Libres</p>
                   <p className="text-xl font-bold text-green-600">{selectedTerminal.totalPorts - getClientsInTerminal(selectedTerminal.id).length}</p>
                </div>
              </div>

              {/* Terminal Ports Grid */}
              <div>
                <h4 className="text-sm font-bold text-gray-700 flex items-center gap-2 mb-2">
                   <ChevronRight className="w-4 h-4 text-blue-500" /> Esquema de Hilos (Splice)
                </h4>
                {renderPortGrid()}
              </div>

              {/* Client List */}
              <div>
                <h4 className="text-sm font-bold text-gray-700 flex items-center gap-2 mb-3">
                   <Users className="w-4 h-4 text-blue-500" /> Clientes en esta NAP
                </h4>
                <div className="space-y-2">
                  {getClientsInTerminal(selectedTerminal.id).map(client => (
                    <div key={client.id} className="p-3 bg-white border border-gray-100 rounded-lg hover:border-blue-200 transition-colors shadow-sm">
                       <div className="flex justify-between items-start">
                          <div>
                             <p className="text-sm font-bold text-gray-800">{client.firstName} {client.lastName}</p>
                             <p className="text-xs text-gray-500 font-mono">Puerto {client.portNumber} | {client.pppoeUser}</p>
                          </div>
                          <span className={`w-2 h-2 rounded-full ${client.status === 'ACTIVE' ? 'bg-green-500' : 'bg-red-500'}`}></span>
                       </div>
                    </div>
                  ))}
                  {getClientsInTerminal(selectedTerminal.id).length === 0 && (
                    <div className="text-center py-8 text-gray-400">
                       <Info className="w-8 h-8 mx-auto mb-2 opacity-20" />
                       <p className="text-xs italic">No hay clientes asignados a esta terminal.</p>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="p-4 border-t border-gray-100 bg-gray-50">
               <button className="w-full bg-blue-600 text-white py-2.5 rounded-xl font-bold text-sm shadow-lg shadow-blue-100 hover:bg-blue-700 transition-colors">
                  Generar Reporte de NAP
               </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default NetworkMap;

