    businessAccountId: ''
  });

  // Handlers for Infrastructure (Terminals)
  const addTerminal = () => {
    const name = prompt('Nombre de la NAP (ej: NAP-Sector1):');
    const lat = prompt('Latitud (ej: 10.48):');
    const lng = prompt('Longitud (ej: -66.90):');
    const pon = prompt('Origen PON (ej: OLT-1 Puerto-1):');
    const ports = prompt('Total Puertos (8 o 16):');

    if (name && lat && lng && pon && ports) {
      const newTerminal: Terminal = {
        id: crypto.randomUUID(),
        name,
        lat: parseFloat(lat),
        lng: parseFloat(lng),
        ponSource: pon,
        totalPorts: parseInt(ports)
      };
      const updated = [...terminals, newTerminal];
      setTerminals(updated);
      storageService.saveTerminals(updated);
    }
  };

  const deleteTerminal = (id: string) => {
    if (confirm('¿Eliminar esta caja NAP del mapa?')) {
      const updated = terminals.filter(t => t.id !== id);
      setTerminals(updated);
      storageService.saveTerminals(updated);
    }
  };

  // Handlers for Routers
  const addRouter = () => {
    const name = prompt('Nombre del Router:');
    const host = prompt('IP o Host:');
    if (name && host) {
      const newRouter: RouterConfig = {
        id: crypto.randomUUID(),
        name,
        host,
        port: 8728,
        user: 'admin',
        pass: '',
        status: 'ONLINE'
      };
      const updated = [...routers, newRouter];
      setRouters(updated);
      storageService.saveRouters(updated);
    }
  };

  const deleteRouter = (id: string) => {
    if (confirm('¿Eliminar conexión de router?')) {
      const updated = routers.filter(r => r.id !== id);
      setRouters(updated);
      storageService.saveRouters(updated);
    }
  };

  // Handlers for Plans
  const handleAddPlan = () => {
    const name = prompt('Nombre del Plan:');
    const speed = prompt('Velocidad:');
    const price = prompt('Precio Mensual:');
    if (name && speed && price) {
      const newPlan: Plan = {
        id: crypto.randomUUID(),
        name,
        speed,
        price: parseFloat(price)
      };
      const updated = [...plans, newPlan];
      setPlans(updated);
      storageService.savePlans(updated);
    }
  };

  const saveWhatsApp = (e: React.FormEvent) => {
    e.preventDefault();
    storageService.saveWhatsAppConfig(waConfig);
    alert('Configuración guardada.');
  };

  const tabs = [
    { id: 'routers', label: 'Routers', icon: Cpu },
    { id: 'infrastructure', label: 'Infraestructura/NAPs', icon: MapPin },
    { id: 'plans', label: 'Planes', icon: Wifi },
    { id: 'whatsapp', label: 'WhatsApp', icon: MessageSquare },
    { id: 'system', label: 'Sistema', icon: ShieldCheck },
