          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
              activeTab === tab.id 
                ? 'bg-blue-600 text-white shadow-md' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <tab.icon className="w-4 h-4" />
            {tab.label}
          </button>
        ))}
      </div>

      <div className="min-h-[500px]">
        {activeTab === 'infrastructure' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold text-gray-900">Infraestructura de Red (NAPs)</h3>
                <p className="text-sm text-gray-500">Administra tus cajas terminales y puntos de distribución de fibra.</p>
              </div>
              <button 
                onClick={addTerminal}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition-colors"
              >
                <Plus className="w-4 h-4" />
                Registrar NAP
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {terminals.map(term => (
                <div key={term.id} className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm relative overflow-hidden group">
                  <div className="flex justify-between items-start mb-4 relative z-10">
                    <div className="bg-blue-50 p-2.5 rounded-lg text-blue-600">
                      <Box className="w-6 h-6" />
                    </div>
                    <div className="flex gap-1">
                      <button onClick={() => deleteTerminal(term.id)} className="p-2 text-gray-400 hover:text-red-600 transition-colors"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>
                  <h4 className="font-bold text-gray-900 text-lg relative z-10">{term.name}</h4>
                  <div className="space-y-1 mt-2 relative z-10">
                    <p className="text-xs text-gray-500 flex items-center gap-1"><Zap className="w-3 h-3" /> PON: {term.ponSource}</p>
                    <p className="text-xs text-gray-500 flex items-center gap-1"><MapPin className="w-3 h-3" /> {term.lat.toFixed(4)}, {term.lng.toFixed(4)}</p>
                  </div>
                  <div className="mt-4 pt-4 border-t border-gray-50 flex justify-between items-center relative z-10">
                     <span className="text-xs font-bold text-gray-400">{term.totalPorts} PUERTOS</span>
                     <span className="text-xs text-blue-600 font-bold bg-blue-50 px-2 py-0.5 rounded-full">Activa</span>
                  </div>
                  {/* Visual Decoration */}
                  <div className="absolute top-0 right-0 p-4 opacity-[0.03] group-hover:opacity-[0.08] transition-opacity">
                     <MapPin className="w-24 h-24 rotate-12" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'routers' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold text-gray-900">Nodos Mikrotik</h3>
              </div>
              <button onClick={addRouter} className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2">
                <Plus className="w-4 h-4" /> Añadir Router
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {routers.map(router => (
                <div key={router.id} className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-blue-50 p-3 rounded-lg text-blue-600"><Cpu className="w-6 h-6" /></div>
                    <button onClick={() => deleteRouter(router.id)} className="p-2 text-gray-400 hover:text-red-600"><Trash2 className="w-4 h-4" /></button>
                  </div>
                  <h4 className="font-bold text-lg text-gray-900">{router.name}</h4>
                  <p className="text-sm text-gray-500">{router.host}:{router.port}</p>
                  <div className="mt-4 pt-4 border-t border-gray-50 flex justify-between items-center">
                    <span className="text-xs font-bold text-green-600">CONECTADO</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'plans' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold text-gray-900">Planes</h3>
              <button onClick={handleAddPlan} className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2">
                <Plus className="w-4 h-4" /> Nuevo Plan
              </button>
