            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {plans.map(plan => (
                <div key={plan.id} className="bg-white p-6 rounded-xl border border-gray-200">
                  <h4 className="font-bold text-lg">{plan.name}</h4>
                  <p className="text-blue-600 font-bold">{plan.speed}</p>
                  <p className="text-2xl font-black mt-4">${plan.price}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'whatsapp' && (
          <div className="max-w-2xl bg-white rounded-2xl p-8 border border-gray-200">
            <h3 className="text-lg font-bold mb-6 flex items-center gap-2"><MessageSquare className="w-5 h-5 text-green-600" /> WhatsApp Meta API</h3>
            <form onSubmit={saveWhatsApp} className="space-y-4">
               <div>
                  <label className="text-xs font-bold text-gray-500 uppercase">Access Token</label>
                  <textarea className="w-full p-3 border border-gray-200 rounded-lg bg-gray-50 text-xs font-mono" rows={3} value={waConfig.accessToken} onChange={e => setWaConfig({...waConfig, accessToken: e.target.value})} />
