  X,
  MapPin,
  Activity
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { Client, ClientStatus, Plan, Terminal } from '../types';

const Clients: React.FC = () => {
  const [clients, setClients] = React.useState<Client[]>(storageService.getClients());
  const [plans] = React.useState<Plan[]>(storageService.getPlans());
  const [terminals] = React.useState<Terminal[]>(storageService.getTerminals());
  const [searchTerm, setSearchTerm] = React.useState('');
  const [isModalOpen, setIsModalOpen] = React.useState(false);

  const [formData, setFormData] = React.useState({
    firstName: '',
    lastName: '',
    phone: '',
    idNumber: '',
    planId: plans[0]?.id || '',
    pppoeUser: '',
    addressList: 'MOROSOS',
    terminalId: '',
    portNumber: 1
  });

  const handleAddClient = (e: React.FormEvent) => {
    e.preventDefault();
    const newClient: Client = {
      id: crypto.randomUUID(),
      ...formData,
      status: ClientStatus.ACTIVE,
      createdAt: new Date().toISOString()
    };
    const updated = [...clients, newClient];
    setClients(updated);
    storageService.saveClients(updated);
    setIsModalOpen(false);
    setFormData({
      firstName: '', lastName: '', phone: '', idNumber: '',
      planId: plans[0]?.id || '', pppoeUser: '', addressList: 'MOROSOS',
      terminalId: '', portNumber: 1
    });
  };

  const toggleStatus = (id: string) => {
    const updated = clients.map(c => 
      c.id === id ? { ...c, status: c.status === ClientStatus.ACTIVE ? ClientStatus.CUT : ClientStatus.ACTIVE } : c
    );
    setClients(updated);
    storageService.saveClients(updated);
  };

  const deleteClient = (id: string) => {
    if (confirm('¿Seguro que deseas eliminar este cliente?')) {
      const updated = clients.filter(c => c.id !== id);
      setClients(updated);
      storageService.saveClients(updated);
    }
  };

  const filteredClients = clients.filter(c => 
    `${c.firstName} ${c.lastName}`.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.idNumber.includes(searchTerm) ||
    c.pppoeUser.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative flex-1 w-full max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            placeholder="Buscar por nombre, ID o usuario PPPoE..."
            className="w-full pl-10 pr-4 py-2 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 w-full sm:w-auto justify-center"
        >
          <Plus className="w-4 h-4" />
          Nuevo Cliente
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Cliente</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Documento / PPPoE</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">NAP/Terminal</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase">Estado</th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredClients.map((client) => {
                const terminal = terminals.find(t => t.id === client.terminalId);
                return (
                  <tr key={client.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-medium text-gray-900">{client.firstName} {client.lastName}</div>
                      <div className="text-xs text-gray-500">{client.phone}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-700">{client.idNumber}</div>
                      <div className="text-xs font-mono text-blue-600">{client.pppoeUser}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <MapPin className="w-4 h-4 text-gray-400" />
                        <div className="text-sm text-gray-700">
                          {terminal ? `${terminal.name} (P-${client.portNumber})` : <span className="text-gray-400 italic">No asignado</span>}
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2.5 py-1 rounded-full text-xs font-medium inline-flex items-center gap-1 ${
                        client.status === ClientStatus.ACTIVE ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {client.status === ClientStatus.ACTIVE ? <UserCheck className="w-3 h-3" /> : <UserX className="w-3 h-3" />}
                        {client.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <button onClick={() => toggleStatus(client.id)} className={`p-2 rounded-lg ${client.status === ClientStatus.ACTIVE ? 'text-orange-500 hover:bg-orange-50' : 'text-green-500 hover:bg-green-50'}`}>
                          {client.status === ClientStatus.ACTIVE ? <WifiOff className="w-4 h-4" /> : <Wifi className="w-4 h-4" />}
                        </button>
                        <button onClick={() => deleteClient(client.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredClients.length === 0 && <div className="p-12 text-center text-gray-500">No se encontraron clientes.</div>}
        </div>
      </div>

      {/* Add Client Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden overflow-y-auto max-h-[90vh]">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <h3 className="text-xl font-bold text-gray-800">Registrar Nuevo Cliente</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                <X className="w-6 h-6" />
              </button>
            </div>
            <form onSubmit={handleAddClient} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Nombre</label>
                  <input required className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Apellido</label>
                  <input required className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">WhatsApp</label>
                  <input required className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-gray-500 uppercase">Cédula/RIF</label>
                  <input required className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.idNumber} onChange={e => setFormData({...formData, idNumber: e.target.value})} />
                </div>
              </div>

              <div className="border-t border-gray-100 pt-4">
                 <h4 className="text-xs font-bold text-blue-600 uppercase mb-3 flex items-center gap-2"><Activity className="w-3 h-3" /> Conexión y Red</h4>
                 <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1">
                      <label className="text-xs font-semibold text-gray-500 uppercase">Caja NAP / Terminal</label>
                      <select required className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.terminalId} onChange={e => setFormData({...formData, terminalId: e.target.value})}>
                        <option value="">Seleccionar NAP...</option>
                        {terminals.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                      </select>
                   </div>
                   <div className="space-y-1">
                      <label className="text-xs font-semibold text-gray-500 uppercase">Puerto (Hilo)</label>
                      <input required type="number" min="1" max="16" className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.portNumber} onChange={e => setFormData({...formData, portNumber: parseInt(e.target.value)})} />
                   </div>
                 </div>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase">Plan</label>
                <select className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.planId} onChange={e => setFormData({...formData, planId: e.target.value})}>
                  {plans.map(p => <option key={p.id} value={p.id}>{p.name} - ${p.price}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase">Usuario PPPoE</label>
                <input required className="w-full px-3 py-2 border border-gray-200 rounded-lg" value={formData.pppoeUser} onChange={e => setFormData({...formData, pppoeUser: e.target.value})} />
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white py-3 rounded-lg font-bold mt-4 shadow-lg shadow-blue-100">Guardar Cliente</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Clients;

