        id: crypto.randomUUID(),
        name,
        host,
        port: 8728,
        user: 'admin',
        pass: '',
        status: 'ONLINE'
      };
      const updated = [...routers, newRouter];
      setRouters(updated);
      storageService.saveRouters(updated);
    }
  };

  const deleteRouter = (id: string) => {
    if (confirm('¿Eliminar conexión de router?')) {
      const updated = routers.filter(r => r.id !== id);
      setRouters(updated);
      storageService.saveRouters(updated);
    }
