                  {getClientsInTerminal(selectedTerminal.id).map(client => (
                    <div key={client.id} className="p-3 bg-white border border-gray-100 rounded-lg hover:border-blue-200 transition-colors shadow-sm">
                       <div className="flex justify-between items-start">
                          <div>
                             <p className="text-sm font-bold text-gray-800">{client.firstName} {client.lastName}</p>
                             <p className="text-xs text-gray-500 font-mono">Puerto {client.portNumber} | {client.pppoeUser}</p>
