const KEYS = {
  CLIENTS: 'rrnet_clients',
  PLANS: 'rrnet_plans',
  INVOICES: 'rrnet_invoices',
  ROUTERS: 'rrnet_routers',
  WA_CONFIG: 'rrnet_wa_config',
  TERMINALS: 'rrnet_terminals',
  CABLES: 'rrnet_cables',
};

const DEFAULT_PLANS: Plan[] = [
  { id: 'p1', name: 'Plan Básico', speed: '10 Mbps', price: 15.00 },
  { id: 'p2', name: 'Plan Estándar', speed: '20 Mbps', price: 25.00 },
  { id: 'p3', name: 'Plan Premium', speed: '50 Mbps', price: 45.00 },
];

export const storageService = {
  getClients: (): Client[] => {
    const data = localStorage.getItem(KEYS.CLIENTS);
    return data ? JSON.parse(data) : [];
  },
  saveClients: (clients: Client[]) => {
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  getPlans: (): Plan[] => {
    const data = localStorage.getItem(KEYS.PLANS);
    return data ? JSON.parse(data) : DEFAULT_PLANS;
  },
  savePlans: (plans: Plan[]) => {
    localStorage.setItem(KEYS.PLANS, JSON.stringify(plans));
  },
  getInvoices: (): Invoice[] => {
    const data = localStorage.getItem(KEYS.INVOICES);
    return data ? JSON.parse(data) : [];
  },
  saveInvoices: (invoices: Invoice[]) => {
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },
  getRouters: (): RouterConfig[] => {
    const data = localStorage.getItem(KEYS.ROUTERS);
    return data ? JSON.parse(data) : [];
  },
  saveRouters: (routers: RouterConfig[]) => {
    localStorage.setItem(KEYS.ROUTERS, JSON.stringify(routers));
  },
  getWhatsAppConfig: (): WhatsAppConfig | null => {
    const data = localStorage.getItem(KEYS.WA_CONFIG);
    return data ? JSON.parse(data) : null;
  },
  saveWhatsAppConfig: (config: WhatsAppConfig) => {
    localStorage.setItem(KEYS.WA_CONFIG, JSON.stringify(config));
  },
  getTerminals: (): Terminal[] => {
    const data = localStorage.getItem(KEYS.TERMINALS);
    return data ? JSON.parse(data) : [];
  },
  saveTerminals: (terminals: Terminal[]) => {
    localStorage.setItem(KEYS.TERMINALS, JSON.stringify(terminals));
  },
  getCables: (): Cable[] => {
    const data = localStorage.getItem(KEYS.CABLES);
    return data ? JSON.parse(data) : [];
  },
  saveCables: (cables: Cable[]) => {
    localStorage.setItem(KEYS.CABLES, JSON.stringify(cables));
  }
};

import React from 'react';
import { 
  Box, 
  Users, 
  MapPin, 
  Zap, 
  X, 
  Search, 
  Info,
  ChevronRight,
  Activity,
  MousePointer2,
  PlusCircle,
  GitBranch,
  Navigation,
  Trash2,
  Save
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { Terminal, Client, Cable } from '../types';

declare const L: any;

type MapMode = 'VIEW' | 'ADD_NAP' | 'DRAW_CABLE';

const NetworkMap: React.FC = () => {
  const mapRef = React.useRef<any>(null);
  const [mode, setMode] = React.useState<MapMode>('VIEW');
  const [terminals, setTerminals] = React.useState<Terminal[]>(storageService.getTerminals());
  const [cables, setCables] = React.useState<Cable[]>(storageService.getCables());
  const [clients] = React.useState<Client[]>(storageService.getClients());
  const [selectedTerminal, setSelectedTerminal] = React.useState<Terminal | null>(null);

  // Temporary state for drawing
  const [tempPoints, setTempPoints] = React.useState<[number, number][]>([]);
  const tempPolylineRef = React.useRef<any>(null);

  React.useEffect(() => {
    if (!mapRef.current) {
      mapRef.current = L.map('network-map', { zoomControl: false }).setView([10.4806, -66.9036], 13);
      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; OpenStreetMap',
        maxZoom: 20
      }).addTo(mapRef.current);

      // Map Click Handler
      mapRef.current.on('click', (e: any) => {
        const { lat, lng } = e.latlng;

        setMode(currentMode => {
          if (currentMode === 'ADD_NAP') {
            const name = prompt('Nombre de la nueva NAP:');
            if (name) {
              const newTerm: Terminal = {
                id: crypto.randomUUID(),
                name,
                lat,
                lng,
                ponSource: 'Pendiente',
                totalPorts: 16
              };
              const updated = [...storageService.getTerminals(), newTerm];
              storageService.saveTerminals(updated);
              setTerminals(updated);
            }
            return 'VIEW';
          }

          if (currentMode === 'DRAW_CABLE') {
            setTempPoints(prev => [...prev, [lat, lng]]);
            return currentMode;
          }

          return currentMode;
        });
      });
    }

    renderLayers();
  }, [terminals, cables, mode, tempPoints]);

  const renderLayers = () => {
    if (!mapRef.current) return;

    // Clear previous layers
    mapRef.current.eachLayer((layer: any) => {
      if (layer instanceof L.Marker || layer instanceof L.Polyline) {
        if (layer !== tempPolylineRef.current) {
          mapRef.current.removeLayer(layer);
        }
      }
    });

    // Render Cables
    cables.forEach(cable => {
      L.polyline(cable.points, { 
        color: cable.color || '#3b82f6', 
        weight: 4,
        opacity: 0.8 
      }).addTo(mapRef.current).bindPopup(`Cable: ${cable.name}`);
    });

    // Render Terminals
    terminals.forEach(term => {
      const marker = L.marker([term.lat, term.lng], {
        icon: L.divIcon({
          className: 'custom-div-icon',
          html: `<div class="bg-blue-600 p-2 rounded-lg border-2 border-white shadow-lg text-white flex items-center justify-center transition-transform hover:scale-110">
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"></path><path d="m3.3 7 8.7 5 8.7-5"></path><path d="M12 22V12"></path></svg>
                 </div>`,
          iconSize: [32, 32],
          iconAnchor: [16, 16]
        })
      }).addTo(mapRef.current);

      marker.on('click', (e: any) => {
        L.DomEvent.stopPropagation(e);
        setSelectedTerminal(term);
      });
    });

    // Render Temp Drawing Polyline
    if (tempPoints.length > 0) {
      if (tempPolylineRef.current) mapRef.current.removeLayer(tempPolylineRef.current);
      tempPolylineRef.current = L.polyline(tempPoints, { color: '#ef4444', dashArray: '5, 10' }).addTo(mapRef.current);
    }
  };

  const saveCurrentCable = () => {
    if (tempPoints.length < 2) return;
    const name = prompt('Nombre del cable/enlace:');
    if (name) {
      const newCable: Cable = {
        id: crypto.randomUUID(),
        name,
        type: 'DISTRIBUTION',
        points: tempPoints,
        color: '#3b82f6'
      };
      const updated = [...cables, newCable];
      setCables(updated);
      storageService.saveCables(updated);
    }
    setTempPoints([]);
    setMode('VIEW');
  };

  const locateMe = () => {
    mapRef.current.locate({ setView: true, maxZoom: 16 });
  };

  const getClientsInTerminal = (termId: string) => clients.filter(c => c.terminalId === termId);

  return (
    <div className="h-full relative flex flex-col md:flex-row bg-gray-900">
      {/* Map Toolbar */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[1000] flex items-center gap-1 bg-white/90 backdrop-blur-md p-1 rounded-2xl shadow-2xl border border-white/20">
        <button 
          onClick={() => { setMode('VIEW'); setTempPoints([]); }}
          className={`p-3 rounded-xl transition-all flex items-center gap-2 ${mode === 'VIEW' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 text-gray-600'}`}
          title="Modo Vista"
        >
          <MousePointer2 className="w-5 h-5" />
          <span className="text-xs font-bold hidden sm:inline">Navegar</span>
        </button>
        <button 
          onClick={() => { setMode('ADD_NAP'); setTempPoints([]); }}
          className={`p-3 rounded-xl transition-all flex items-center gap-2 ${mode === 'ADD_NAP' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 text-gray-600'}`}
          title="Añadir Caja NAP"
        >
          <PlusCircle className="w-5 h-5" />
          <span className="text-xs font-bold hidden sm:inline">Añadir NAP</span>
        </button>
        <button 
          onClick={() => setMode('DRAW_CABLE')}
          className={`p-3 rounded-xl transition-all flex items-center gap-2 ${mode === 'DRAW_CABLE' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 text-gray-600'}`}
          title="Trazar Fibra"
        >
          <GitBranch className="w-5 h-5" />
          <span className="text-xs font-bold hidden sm:inline">Trazar Fibra</span>
        </button>
        <div className="w-px h-6 bg-gray-200 mx-1"></div>
        <button 
          onClick={locateMe}
          className="p-3 rounded-xl hover:bg-gray-100 text-blue-600 transition-all"
          title="Mi ubicación"
        >
          <Navigation className="w-5 h-5" />
        </button>
      </div>

      {/* Floating Save Cable Button */}
      {tempPoints.length > 1 && mode === 'DRAW_CABLE' && (
        <button 
          onClick={saveCurrentCable}
          className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1000] bg-green-600 text-white px-8 py-3 rounded-2xl shadow-2xl font-bold flex items-center gap-2 hover:bg-green-700 animate-bounce"
        >
          <Save className="w-5 h-5" />
          Guardar Trazo de Fibra
        </button>
      )}

      {/* Map Content */}
      <div className="flex-1 relative">
        <div id="network-map" className="absolute inset-0"></div>

        {/* Helper Hint */}
        <div className="absolute bottom-4 left-4 z-[1000] bg-black/60 backdrop-blur-md text-white px-4 py-2 rounded-xl text-xs border border-white/10 pointer-events-none">
          {mode === 'VIEW' && "Selecciona una caja para ver detalles"}
          {mode === 'ADD_NAP' && "Haz clic en el mapa para posicionar una NAP"}
          {mode === 'DRAW_CABLE' && "Haz clic en varios puntos para trazar la ruta de la fibra"}
        </div>
      </div>

      {/* Sidebar Details (Copy-pasted logic from original but styled for dark/light) */}
      <div className={`
        fixed inset-y-0 right-0 w-full sm:w-80 bg-white shadow-2xl z-[2000] transform transition-transform duration-300 border-l border-gray-200 flex flex-col
        ${selectedTerminal ? 'translate-x-0' : 'translate-x-full'}
      `}>
        {selectedTerminal && (
          <>
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-blue-600 text-white">
              <div>
                <h3 className="font-bold text-lg">{selectedTerminal.name}</h3>
                <p className="text-xs text-blue-100 flex items-center gap-1">
                   <Zap className="w-3 h-3" /> PON: {selectedTerminal.ponSource}
                </p>
              </div>
              <button onClick={() => setSelectedTerminal(null)} className="p-1.5 hover:bg-white/20 rounded-lg transition-colors">
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 flex justify-around">
                <div className="text-center">
                   <p className="text-[10px] text-gray-500 font-bold uppercase">Puertos</p>
                   <p className="text-xl font-bold text-gray-800">{selectedTerminal.totalPorts}</p>
                </div>
                <div className="text-center">
                   <p className="text-[10px] text-gray-500 font-bold uppercase">Clientes</p>
                   <p className="text-xl font-bold text-blue-600">{getClientsInTerminal(selectedTerminal.id).length}</p>
                </div>
              </div>

              <div className="space-y-4">
                 <h4 className="text-sm font-bold text-gray-700 flex items-center gap-2">
                    <Users className="w-4 h-4 text-blue-500" /> Clientes Conectados
                 </h4>
                 {getClientsInTerminal(selectedTerminal.id).map(client => (
                   <div key={client.id} className="p-3 bg-white border border-gray-100 rounded-lg shadow-sm">
                      <p className="text-sm font-bold text-gray-800">{client.firstName} {client.lastName}</p>
                      <p className="text-xs text-gray-500">Puerto: {client.portNumber} | {client.pppoeUser}</p>
                   </div>
                 ))}
                 {getClientsInTerminal(selectedTerminal.id).length === 0 && (
                   <p className="text-center text-xs text-gray-400 py-4 italic">No hay clientes asignados.</p>
                 )}
              </div>
            </div>
            <div className="p-4 bg-gray-50 border-t border-gray-100">
               <button 
                onClick={() => {
                  if(confirm('¿Eliminar esta caja?')) {
                    const updated = terminals.filter(t => t.id !== selectedTerminal.id);
                    setTerminals(updated);
                    storageService.saveTerminals(updated);
                    setSelectedTerminal(null);
                  }
                }}
                className="w-full flex items-center justify-center gap-2 py-2 text-red-600 font-bold text-sm hover:bg-red-50 rounded-lg transition-colors"
               >
                 <Trash2 className="w-4 h-4" /> Eliminar NAP
               </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

