          className="p-3 rounded-xl hover:bg-gray-100 text-blue-600 transition-all"
          title="Mi ubicación"
        >
          <Navigation className="w-5 h-5" />
        </button>
      </div>

      {/* Drawing Actions Container */}
      {mode === 'DRAW_CABLE' && (
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1000] flex gap-3">
          <button 
            onClick={cancelDrawing}
            className="bg-white text-gray-700 px-6 py-3 rounded-2xl shadow-xl font-bold flex items-center gap-2 hover:bg-gray-50 border border-gray-200"
          >
            <X className="w-5 h-5" />
            Cancelar
          </button>
          {tempPoints.length > 1 && (
            <button 
              onClick={saveCurrentCable}
              className="bg-green-600 text-white px-8 py-3 rounded-2xl shadow-xl font-bold flex items-center gap-2 hover:bg-green-700 animate-pulse"
            >
              <Save className="w-5 h-5" />
