      {/* Map Content */}
      <div className="flex-1 relative">
        <div id="network-map" className="absolute inset-0 bg-gray-200"></div>

        {/* Tooltip hint */}
        {mode !== 'VIEW' && (
          <div className="absolute top-20 left-1/2 -translate-x-1/2 z-[1000] bg-blue-900/80 backdrop-blur-sm text-white px-4 py-2 rounded-full text-xs font-medium border border-blue-400/30">
            {mode === 'ADD_NAP' ? 'Haz clic en el mapa para colocar la caja' : 'Haz clic en varios puntos para dibujar la ruta'}
          </div>
        )}
      </div>

      {/* Info Sidebar */}
      <div className={`
        fixed inset-y-0 right-0 w-full sm:w-80 bg-white shadow-2xl z-[2000] transform transition-transform duration-300 border-l border-gray-200 flex flex-col
        ${selectedTerminal ? 'translate-x-0' : 'translate-x-full'}
