                 </div>`,
          iconSize: [32, 32],
          iconAnchor: [16, 16]
        })
      }).addTo(markersGroupRef.current);

      marker.on('click', (e: any) => {
        L.DomEvent.stopPropagation(e);
        setSelectedTerminal(term);
      });
    });
  }, [terminals, cables]);

  // 4. Render Temporary Drawing Line
  React.useEffect(() => {
    if (!mapRef.current) return;
    if (tempPolylineRef.current) mapRef.current.removeLayer(tempPolylineRef.current);

    if (tempPoints.length > 0) {
      tempPolylineRef.current = L.polyline(tempPoints, { 
        color: '#ef4444', 
        dashArray: '10, 10',
        weight: 4,
        opacity: 0.8
      }).addTo(mapRef.current);
    }
  }, [tempPoints]);

  const saveCurrentCable = () => {
    if (tempPoints.length < 2) return;
    const name = prompt('Nombre del enlace:');
    if (name) {
      const newCable: Cable = {
        id: crypto.randomUUID(),
        name,
        type: 'DISTRIBUTION',
        points: tempPoints,
        color: '#3b82f6'
      };
      setCables(prev => {
        const updated = [...prev, newCable];
        storageService.saveCables(updated);
        return updated;
      });
      setNotification(`Cable "${name}" guardado`);
    }
    setTempPoints([]);
    setMode('VIEW');
  };

  const locateMe = () => {
    mapRef.current.locate({ setView: true, maxZoom: 16 });
  };

  const getClientsInTerminal = (termId: string) => clients.filter(c => c.terminalId === termId);

  return (
    <div className="h-full relative flex flex-col md:flex-row bg-gray-50 overflow-hidden">
      {/* Toast Notification */}
      {notification && (
        <div className="absolute top-20 right-4 z-[3000] bg-green-600 text-white px-6 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-bounce">
          <CheckCircle2 className="w-5 h-5" />
          <span className="font-bold text-sm">{notification}</span>
        </div>
      )}

      {/* Map Toolbar */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[1000] flex items-center gap-1 bg-white p-1.5 rounded-2xl shadow-2xl border border-gray-200">
        <button 
          onClick={() => { setMode('VIEW'); setTempPoints([]); }}
          className={`p-3 rounded-xl transition-all flex items-center gap-2 ${mode === 'VIEW' ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-gray-100 text-gray-600'}`}
