          onClick={() => { setMode('ADD_NAP'); setTempPoints([]); }}
          className={`p-3 rounded-xl transition-all flex items-center gap-2 ${mode === 'ADD_NAP' ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-gray-100 text-gray-600'}`}
