          <span className="text-xs font-bold hidden lg:inline">Añadir NAP</span>
        </button>
        <button 
          onClick={() => { setMode('DRAW_CABLE'); setTempPoints([]); }}
          className={`p-3 rounded-xl transition-all flex items-center gap-2 ${mode === 'DRAW_CABLE' ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-gray-100 text-gray-600'}`}
        >
          <GitBranch className="w-5 h-5" />
          <span className="text-xs font-bold hidden lg:inline">Trazar Fibra</span>
        </button>
        <div className="w-px h-6 bg-gray-200 mx-1"></div>
        <button 
