      {/* Drawing Actions */}
      {mode === 'DRAW_CABLE' && tempPoints.length > 1 && (
        <button 
          onClick={saveCurrentCable}
          className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1000] bg-green-600 text-white px-8 py-3 rounded-2xl shadow-2xl font-bold flex items-center gap-2 hover:bg-green-700 transition-all scale-110"
        >
          <Save className="w-5 h-5" />
          Finalizar Enlace
        </button>
      )}

      {/* Map Content */}
      <div className="flex-1 relative">
