import React from 'react';
import { 
  Download, 
  Plus, 
  Trash2, 
  DollarSign, 
  TrendingUp, 
  Wallet,
  ArrowDownCircle,
  PiggyBank,
  PieChart as PieIcon,
  X
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { InvoiceStatus, ZoneType, Expense, Client, Invoice } from '../types';

const Reports: React.FC = () => {
  const [invoices] = React.useState<Invoice[]>(storageService.getInvoices());
  const [clients] = React.useState<Client[]>(storageService.getClients());
  const [expenses, setExpenses] = React.useState<Expense[]>(storageService.getExpenses());
  const [balances, setBalances] = React.useState(storageService.getBankBalances());
  const [showExpenseModal, setShowExpenseModal] = React.useState(false);

  const [newExpense, setNewExpense] = React.useState({ description: '', amount: 0 });

  // Agrupar Ingresos por Zona
  const getIncomeByZone = (zone: ZoneType) => {
    return invoices
      .filter(inv => {
        const client = clients.find(c => c.id === inv.clientId);
        return inv.status === InvoiceStatus.PAID && client?.zone === zone;
      })
      .reduce((sum, inv) => sum + inv.amount, 0);
  };

  const incomeRR = getIncomeByZone('R&RNETWORK');
  const incomeRV = getIncomeByZone('RV NETWORK');
  const incomeRB = getIncomeByZone('RB NETWORK');
  const totalGross = incomeRR + incomeRV + incomeRB;

  const totalExpenses = expenses.reduce((sum, e) => sum + e.amount, 0);
  const totalNet = totalGross - totalExpenses;

  // Repartición Socios
  // Tu regla: Cada quien cobra sus clientes por separado (RV y RB) 
  // y dividen gastos de lo que genera R&RNETWORK (65/35)
  const raymerNet = incomeRV + (incomeRR * 0.65) - (totalExpenses * 0.65);
  const memoNet = incomeRB + (incomeRR * 0.35) - (totalExpenses * 0.35);

  const handleAddExpense = () => {
    if (!newExpense.description || newExpense.amount <= 0) return;
    const expense: Expense = {
      id: crypto.randomUUID(),
      description: newExpense.description,
      amount: newExpense.amount,
      category: 'General',
      date: new Date().toISOString()
    };
    const updated = [...expenses, expense];
    setExpenses(updated);
    storageService.saveExpenses(updated);
    setShowExpenseModal(false);
    setNewExpense({ description: '', amount: 0 });
  };

  const deleteExpense = (id: string) => {
    const updated = expenses.filter(e => e.id !== id);
    setExpenses(updated);
    storageService.saveExpenses(updated);
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(val);
  };

  return (
    <div className="p-2 sm:p-6 space-y-8 max-w-4xl mx-auto overflow-y-auto h-full no-scrollbar pb-24">

      {/* Header Actions */}
      <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
        <div>
           <h2 className="text-2xl font-black text-gray-800 tracking-tight">Reporte Interno</h2>
           <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">{new Date().toLocaleString('es-ES', { month: 'long', year: 'numeric' })}</p>
        </div>
        <button className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-100">
          <Download className="w-5 h-5" />
        </button>
      </div>

      <div className="grid grid-cols-1 gap-8">

        {/* INGRESOS POR ZONAS */}
        <div className="bg-white rounded-xl shadow-xl border-2 border-gray-100 overflow-hidden">
          <div className="bg-blue-700 text-white p-3 text-center">
            <h3 className="font-black uppercase tracking-widest text-sm">Ingresos por Zonas</h3>
          </div>
          <table className="w-full">
            <tbody className="text-sm font-bold divide-y divide-gray-100">
              <tr className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 text-gray-600">R&RNETWORK</td>
                <td className="px-6 py-4 text-right">{formatCurrency(incomeRR)}</td>
              </tr>
              <tr className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 text-gray-600">RV NETWORK (Raymer)</td>
                <td className="px-6 py-4 text-right">{formatCurrency(incomeRV)}</td>
              </tr>
              <tr className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 text-gray-600">RB NETWORK (Memo)</td>
                <td className="px-6 py-4 text-right">{formatCurrency(incomeRB)}</td>
              </tr>
            </tbody>
            <tfoot>
              <tr className="bg-green-400 text-green-900 font-black">
                <td className="px-6 py-4 uppercase tracking-tighter">Total Bruto RD$</td>
                <td className="px-6 py-4 text-right">{formatCurrency(totalGross)}</td>
              </tr>
            </tfoot>
          </table>
        </div>

        {/* GASTOS */}
        <div className="bg-white rounded-xl shadow-xl border-2 border-gray-100 overflow-hidden">
          <div className="bg-blue-700 text-white p-3 flex justify-between items-center">
            <span className="flex-1 text-center font-black uppercase tracking-widest text-sm ml-8">Gastos</span>
            <button onClick={() => setShowExpenseModal(true)} className="bg-white/20 hover:bg-white/30 p-1.5 rounded-lg transition-all">
              <Plus className="w-4 h-4" />
            </button>
          </div>
          <table className="w-full">
            <tbody className="text-sm font-bold divide-y divide-gray-100">
              {expenses.map(exp => (
                <tr key={exp.id} className="group hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4 text-gray-600 flex items-center gap-3">
                    <button onClick={() => deleteExpense(exp.id)} className="opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-600 transition-all">
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                    {exp.description}
                  </td>
                  <td className="px-6 py-4 text-right">{formatCurrency(exp.amount)}</td>
                </tr>
              ))}
              {expenses.length === 0 && (
                <tr><td colSpan={2} className="px-6 py-10 text-center text-gray-400 italic">No hay gastos registrados</td></tr>
              )}
            </tbody>
            <tfoot>
              <tr className="bg-orange-300 text-orange-900 font-black">
                <td className="px-6 py-4 uppercase tracking-tighter">Total Gastos RD$</td>
                <td className="px-6 py-4 text-right">{formatCurrency(totalExpenses)}</td>
              </tr>
            </tfoot>
          </table>
        </div>

        {/* GANANCIAS NETAS */}
        <div className="bg-white rounded-xl shadow-xl border-2 border-gray-100 overflow-hidden">
          <div className="bg-blue-700 text-white p-3 text-center">
            <h3 className="font-black uppercase tracking-widest text-sm">Ganancias Netas</h3>
          </div>
          <table className="w-full">
            <tbody className="text-sm font-bold divide-y divide-gray-100">
              <tr className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 text-gray-600">Raymer (65% del residual + propio)</td>
                <td className="px-6 py-4 text-right text-blue-600">{formatCurrency(raymerNet)}</td>
              </tr>
              <tr className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 text-gray-600">Memo (35% del residual + propio)</td>
                <td className="px-6 py-4 text-right text-purple-600">{formatCurrency(memoNet)}</td>
              </tr>
            </tbody>
            <tfoot>
              <tr className="bg-green-600 text-white font-black">
                <td className="px-6 py-4 uppercase tracking-tighter">Total Neto RD$</td>
                <td className="px-6 py-4 text-right">{formatCurrency(totalNet)}</td>
              </tr>
            </tfoot>
          </table>
        </div>

        {/* ESTADOS DE CUENTA */}
        <div className="bg-white p-6 rounded-xl border-2 border-gray-100 shadow-sm space-y-4">
           <div className="flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className="bg-blue-100 p-2 rounded-lg"><Wallet className="w-5 h-5 text-blue-600" /></div>
                <span className="font-black text-gray-700 uppercase text-xs tracking-widest">Qik Cuenta</span>
              </div>
              <input 
                type="number" 
                className="text-right font-black text-gray-800 bg-transparent outline-none w-32 border-b-2 border-gray-100 focus:border-blue-500"
                value={balances.qik}
                onChange={(e) => {
                  const val = parseFloat(e.target.value) || 0;
                  setBalances({...balances, qik: val});
                  storageService.saveBankBalances({...balances, qik: val});
                }}
              />
           </div>
           <div className="flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className="bg-orange-100 p-2 rounded-lg"><PiggyBank className="w-5 h-5 text-orange-600" /></div>
                <span className="font-black text-gray-700 uppercase text-xs tracking-widest">Pen. Depositar</span>
              </div>
              <input 
                type="number" 
                className="text-right font-black text-gray-800 bg-transparent outline-none w-32 border-b-2 border-gray-100 focus:border-orange-500"
                value={balances.pending}
                onChange={(e) => {
                  const val = parseFloat(e.target.value) || 0;
                  setBalances({...balances, pending: val});
                  storageService.saveBankBalances({...balances, pending: val});
                }}
              />
           </div>
        </div>

      </div>

      {/* Expense Modal */}
      {showExpenseModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-3xl w-full max-w-sm shadow-2xl overflow-hidden">
            <div className="p-6 bg-blue-600 text-white flex justify-between items-center">
              <h4 className="font-black uppercase tracking-widest text-xs">Añadir Gasto</h4>
              <button onClick={() => setShowExpenseModal(false)}><X className="w-5 h-5" /></button>
            </div>
            <div className="p-8 space-y-4">
               <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Descripción</label>
                  <input 
                    className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none" 
                    placeholder="Ej: Pago Starlink"
                    value={newExpense.description}
                    onChange={(e) => setNewExpense({...newExpense, description: e.target.value})}
                  />
               </div>
               <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Monto RD$</label>
                  <input 
                    type="number" 
                    className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none" 
                    value={newExpense.amount}
                    onChange={(e) => setNewExpense({...newExpense, amount: parseFloat(e.target.value) || 0})}
                  />
               </div>
               <button onClick={handleAddExpense} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase text-xs shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all">
                 Registrar Gasto
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

