    const data = localStorage.getItem(KEYS.PLANS);
    return data ? JSON.parse(data) : DEFAULT_PLANS;
  },
  savePlans: (plans: Plan[]) => {
    localStorage.setItem(KEYS.PLANS, JSON.stringify(plans));
  },
  getInvoices: (): Invoice[] => {
