  const toggleStatus = (id: string) => {
    const updated = clients.map(c => 
      c.id === id ? { ...c, status: c.status === ClientStatus.ACTIVE ? ClientStatus.CUT : ClientStatus.ACTIVE } : c
    );
    setClients(updated);
    storageService.saveClients(updated);
