import React from 'react';
import { 
  Plus, 
  Trash2, 
  ArrowRightLeft, 
  Search,
  X,
  CreditCard,
  Zap,
  CheckCircle2,
  Calendar,
  DollarSign
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { Expense } from '../types';

const Expenses: React.FC = () => {
  const [expenses, setExpenses] = React.useState<Expense[]>(storageService.getExpenses());
  const [showModal, setShowModal] = React.useState(false);
  const [searchTerm, setSearchTerm] = React.useState('');
  const [notification, setNotification] = React.useState<string | null>(null);

  const [newExpense, setNewExpense] = React.useState({ 
    description: '', 
    amount: 0,
    category: 'General'
  });

  const fixedOptions = [
    { label: 'Dedicado', amount: 5000 },
    { label: 'Starlink', amount: 3200 },
    { label: 'Netflix', amount: 800 },
  ];

  const handleAddExpense = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!newExpense.description || newExpense.amount <= 0) return;

    const expense: Expense = {
      id: crypto.randomUUID(),
      description: newExpense.description,
      amount: newExpense.amount,
      category: newExpense.category,
      date: new Date().toISOString()
    };
    const updated = [...expenses, expense];
    setExpenses(updated);
    storageService.saveExpenses(updated);
    setShowModal(false);
    resetForm();
    showNotify('Gasto registrado con éxito');
  };

  const addFixed = (label: string, amount: number) => {
    setNewExpense({ description: label, amount, category: 'Fijo' });
    setShowModal(true);
  };

  const deleteExpense = (id: string) => {
    if (confirm('¿Eliminar este registro de gasto?')) {
      const updated = expenses.filter(e => e.id !== id);
      setExpenses(updated);
      storageService.saveExpenses(updated);
    }
  };

  const resetForm = () => {
    setNewExpense({ description: '', amount: 0, category: 'General' });
  };

  const showNotify = (msg: string) => {
    setNotification(msg);
    setTimeout(() => setNotification(null), 3000);
  };

  const filteredExpenses = expenses.filter(e => 
    e.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="h-full flex flex-col space-y-6">

      {notification && (
        <div className="fixed top-20 right-4 z-[100] bg-orange-600 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in fade-in slide-in-from-right-10">
          <CheckCircle2 className="w-5 h-5" />
          <p className="font-bold text-sm">{notification}</p>
        </div>
      )}

      {/* Header Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex gap-2">
           {fixedOptions.map(opt => (
             <button 
                key={opt.label}
                onClick={() => addFixed(opt.label, opt.amount)}
                className="bg-white px-4 py-2 rounded-xl border border-gray-100 shadow-sm hover:bg-blue-50 hover:text-blue-600 hover:border-blue-100 transition-all text-xs font-black uppercase tracking-wider text-gray-500 flex items-center gap-2"
             >
               <Zap className="w-3.5 h-3.5" />
               {opt.label}
             </button>
           ))}
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-100 flex items-center gap-2 hover:bg-blue-700 active:scale-95 transition-all"
        >
          <Plus className="w-4 h-4" />
          Registrar Gasto
        </button>
      </div>

      <div className="relative w-full max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
        <input 
          type="text" 
          placeholder="Buscar gastos..."
          className="w-full pl-10 pr-4 py-3 bg-white border border-gray-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
          value={searchTerm}
          onChange={e => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Expenses Table */}
      <div className="bg-white rounded-3xl border border-gray-50 shadow-sm overflow-hidden flex-1 flex flex-col">
        <div className="overflow-y-auto no-scrollbar flex-1">
          <table className="w-full text-left">
            <thead className="bg-gray-50/50 sticky top-0 backdrop-blur-md">
              <tr className="border-b border-gray-100">
                <th className="px-8 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Descripción</th>
                <th className="px-8 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Monto</th>
                <th className="px-8 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest text-right">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filteredExpenses.slice().reverse().map(exp => (
                <tr key={exp.id} className="group hover:bg-gray-50 transition-colors">
                  <td className="px-8 py-4">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-gray-100 rounded-lg group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                        <CreditCard className="w-4 h-4" />
                      </div>
                      <div>
                        <p className="font-bold text-gray-800">{exp.description}</p>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{exp.category}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-4">
                    <span className="font-black text-gray-900">RD${exp.amount.toLocaleString()}</span>
                  </td>
                  <td className="px-8 py-4 text-right">
                    <button 
                      onClick={() => deleteExpense(exp.id)}
                      className="p-2 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredExpenses.length === 0 && (
            <div className="p-20 text-center flex flex-col items-center justify-center space-y-4 opacity-30">
              <ArrowRightLeft className="w-16 h-16 text-gray-400" />
              <p className="font-bold text-gray-500 uppercase tracking-widest text-xs">No hay gastos registrados este mes</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-[40px] w-full max-w-sm shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="p-8 bg-blue-600 text-white flex justify-between items-center">
              <div>
                <h4 className="font-black uppercase tracking-widest text-xs">Añadir Egreso</h4>
                <p className="text-[10px] text-blue-100 mt-1 uppercase font-bold tracking-tight">Registro contable de red</p>
              </div>
              <button onClick={() => setShowModal(false)} className="hover:bg-white/20 p-2 rounded-full"><X className="w-6 h-6" /></button>
            </div>
            <form onSubmit={handleAddExpense} className="p-10 space-y-6">
               <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Descripción del Gasto</label>
                  <input 
                    required
                    className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-blue-500 focus:bg-white rounded-2xl outline-none font-bold transition-all" 
                    placeholder="Ej: Starlink"
                    value={newExpense.description}
                    onChange={(e) => setNewExpense({...newExpense, description: e.target.value})}
                  />
               </div>
               <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Monto RD$</label>
                  <div className="relative">
