import { RouterConfig } from '../types';

export interface MikrotikResource {
  cpu: string;
  uptime: string;
  version: string;
  boardName: string;
}

export const mikrotikService = {
  /**
   * Genera el header de autorización básica
   */
  getAuthHeader: (router: RouterConfig) => {
    const auth = btoa(`${router.user}:${router.pass}`);
    return { 'Authorization': `Basic ${auth}` };
  },

  /**
   * Prueba la conexión básica al Router (Requiere RouterOS 7.1+)
   */
  testConnection: async (router: RouterConfig): Promise<{success: boolean, data?: MikrotikResource, error?: string}> => {
    try {
      // Nota: En un entorno real, si el router no tiene SSL válido, 
      // el navegador podría bloquear la petición.
      const url = `https://${router.host}:${router.port || 443}/rest/system/resource`;

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          ...mikrotikService.getAuthHeader(router),
          'Content-Type': 'application/json'
        },
        // Modo 'cors' es vital para navegadores
        mode: 'cors'
      });

      if (!response.ok) throw new Error(`Error HTTP: ${response.status}`);

      const data = await response.json();
      return { 
        success: true, 
        data: {
          cpu: `${data['cpu-load']}%`,
          uptime: data.uptime,
          version: data.version,
          boardName: data['board-name']
        }
      };
    } catch (err: any) {
      console.error('Mikrotik Connection Error:', err);
      return { 
        success: false, 
        error: err.message || 'No se pudo conectar. Verifique IP/Puerto y si la API REST está activa.' 
      };
    }
  },

  /**
   * Obtiene la lista de secretos PPPoE
   */
  getPPPoESecrets: async (router: RouterConfig) => {
    try {
      const url = `https://${router.host}:${router.port || 443}/rest/ppp/secret`;
      const response = await fetch(url, {
        headers: mikrotikService.getAuthHeader(router)
      });
      return await response.json();
    } catch (err) {
      console.error(err);
      return [];
    }
  },

  /**
   * Desactiva un usuario (Corte de servicio)
   */
  disableUser: async (router: RouterConfig, name: string) => {
    try {
      const url = `https://${router.host}:${router.port || 443}/rest/ppp/secret/${name}`;
      await fetch(url, {
        method: 'PATCH',
        headers: {
          ...mikrotikService.getAuthHeader(router),
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ disabled: "yes" })
      });
      return true;
    } catch (err) {
      return false;
    }
  }
};

